          let turtle = u.storeToTurtle(store.state.rs.tempRdfStore, "");
          turtle = ur.modifyTurtle(turtle);
          console.log(turtle);
          ur.uploadTriples(this.$route.query.location+"i", turtle, false).then((successfulFetch) => {
            console.log(successfulFetch);
          });
        }
    },
