    async convertIFCtoGLTF(IFCtypeString="IFCWINDOW", IFCtype=[IFCWINDOW]){
      const container = document.createElement('div');
      //container.setAttribute('style', "position: absolute; width: 1000px; height: 1000px; margin-right: 8px; margin-top: 3px; z-index: 5");
      //document.body.appendChild(container);
      const viewer = new IfcViewerAPI({ container, backgroundColor: new Color(0xffffff) });
      await viewer.IFC.loader.ifcManager.useWebWorkers(true, './IFCWorker.js');
      await viewer.IFC.setWasmPath('../');
      
      //viewer.grid.setGrid(40);
      //await viewer.IFC.loadIfcUrl('./Mir111Shell.ifc');

      this.ifcloading = true;
      let IFCuri = this.$route.query.location+"home/IFC/building.ifc"
      console.log("IFC uri: "+IFCuri);
      try {
          const res = await window.solid.session.fetch(
            IFCuri, {
              method: "GET",
              credentials: "include",
              });
              console.log(res);
            let filedata = await res.arrayBuffer();
            let fileurl = URL.createObjectURL(new Blob([filedata], { type: "application/x-step"}));
            
            
            // Export to glTF and JSON
            //fileurl = "../Mir111Full.ifc"; // For testing only, Please comment out.
            let buildingTag = "NMH.Y.SYKEHUS.HN.H.MOIRANA.SJOFORSGATA.HOVEDBYGG.";
            const result = await viewer.GLTF.exportIfcFileAsGltf({
                ifcFileUrl: fileurl,
                splitByFloors: true,
                categories: {
                    //walls: [IFCWALL, IFCWALLSTANDARDCASE],
                    //slabs: [IFCSLAB],
                    //windows: [IFCWINDOW],
                    //curtainwalls: [IFCMEMBER, IFCPLATE, IFCCURTAINWALL],
                    //doors: [IFCDOOR]
                    category: IFCtype,
                },
                getProperties: true
            });

            // Download result
            const link = document.createElement('a');
            document.body.appendChild(link);

            const IFCmetadata = await this.getIFCmetaDataFromJson();
            for(const categoryName in result.gltf) {
                const category = result.gltf[categoryName];
                console.log(category);
                for(const levelName in category) {
                    const heightAboveGround = category.height;
                    const file = category[levelName].file;
                    if(file) {
                        let tagString = buildingTag+this.getFloorTagfromJson(IFCmetadata, levelName)+"."+IFCtypeString;
                        link.download = `${tagString}.gltf`;
                        link.href = URL.createObjectURL(file);
                        link.click();
                    }
                }
            }

            for(let jsonFile of result.json) {
                link.download = `${jsonFile.name}.json`;
                link.href = URL.createObjectURL(jsonFile);
                link.click();
            }

            link.remove();
            this.ifcloading = false;
          } catch (error) {
          console.log(error);
        }
    },
