            res.arrayBuffer().then((filedata) => {
              let file = new Blob([filedata]);
              const fr = new FileReader();
              fr.onload = function() {
                  let jsonResult = JSON.parse(this.result);
                  console.log(jsonResult);
                  resolve(jsonResult);
              };
              fr.readAsText(file);
            });
          });
