    zoomToObject() {
      var boundingBox = null;
      var cameraPosX = null;
      var cameraPosY = 5;
      var cameraHeighSetting = 5;
      if(store.state.bv.INTERSECTED){
        boundingBox = new Box3().setFromObject( store.state.bv.INTERSECTED )
      } else {
        boundingBox = new Box3().setFromObject( store.state.bv.focusobject )
      }
      var size = new Vector3();
      size = boundingBox.getSize(size);
      if(size.x >= size.y){ // Find longest side of box
        store.state.bv.camerafocuswidth = size.x;
      } else {
        store.state.bv.camerafocuswidth = size.y;
      }
      let start, previousTimestamp;
      var cameraHeight = 5000;
      var animateDown = false;
      this.CONVERT_TO_SPHERICAL({ lat: store.state.bv.focuslat, long: store.state.bv.focuslong }).then(u => {
        if(store.state.bv.INTERSECTED){
          var target = new Vector3();
          store.state.bv.INTERSECTED.getWorldPosition( target );
          cameraHeighSetting = target.y;
          console.log(target.x);
          console.log(target.z);
          cameraPosX = target.x + (store.state.bv.camerafocuswidth*0.5);
          cameraPosY = target.z + (store.state.bv.camerafocuswidth*0.5);
          store.state.bv.controls.target.set(target.x+(size.x/2), target.y+(size.y/2), target.z-(size.z/2));
        } else {
          cameraPosX = store.state.bv.coords.x + (store.state.bv.camerafocuswidth*0.5);
          cameraPosY = -store.state.bv.coords.y + (store.state.bv.camerafocuswidth*0.5);
        }
        function step(timestamp){
          if(start === undefined){
            start = timestamp;
          }
          const elapsed = timestamp-start;
          if(previousTimestamp !== timestamp){
            if(cameraHeight >= cameraHeighSetting+40){
              cameraHeight = cameraHeight - 60;
            }
            store.state.bv.camera.position.set(cameraPosX, cameraHeight, cameraPosY);
          }
          if(cameraHeight >= cameraHeighSetting+40){
            previousTimestamp = timestamp;
            window.requestAnimationFrame(step);
          }
        }
        window.requestAnimationFrame(step);
      });
      store.state.bv.camera.position.set(cameraPosX, cameraHeight, cameraPosY);
      console.log("Zoom to object");
    },
