import {
  createSolidDataset,
  createThing,
  setThing,
  getThing,
  addUrl,
  addStringNoLocale,
  saveSolidDatasetAt,
  getSolidDataset,
  getThingAll,
  getStringNoLocale,
  getStringNoLocaleAll,
  createContainerAt,
  getPodOwner
} from "@inrupt/solid-client";

var factory = new (require('rdf-data-factory').DataFactory)();
var RdfTerm = require('rdf-string');
var toRdfLiteral = require("rdf-literal").toRdf;
let searchRdfStore = $rdf.graph();

const se = {}

async function streamToArrayBuffer(stream) {
    var bytes = Object.keys(stream).length;
    var myArr = new Uint8Array(bytes)

    for(var i = 0; i < bytes; i++){
        myArr[i] = stream[i].charCodeAt(0);
    }
    return myArr;
}

async function comunicaQuery(sparqlStr,rowFunction,quadStore,callback) {
  var startTime = performance.now();
  const myEngine = Comunica.newEngine();
  const config = { sources: [quadStore] };
  const result = await myEngine.query(sparqlStr, config);
  result.bindingsStream.on('data',(binding)=> {
    for(let field of binding._root.entries){
      let newRow = [];
      // comunica has [ key, value ], rdflib wants { key : vaue }
      for(let field of binding._root.entries){
        newRow[field[0]]=field[1];
      }
      rowFunction(newRow);
    }
  });
  /*result.bindingsStream.on('data', (binding) => {
    console.log(binding.get('?floor').value);
  });*/
  result.bindingsStream.on('end', () => {
    var endTime = performance.now();
    console.log(`Communicaquery used: ${endTime - startTime} milliseconds`);
    callback();
  });
}

async function rdflibQuery(queryString){
  return new Promise(async (resolve,reject)=>{
    try {
      let quadStore = new N3.Store();
      store.state.rs.rdfStore.match(null, null, null).forEach(stm => {
        quadStore.addQuad( stm.subject,stm.predicate,stm.object )
      });
      //let quadStore = store.state.rs.rdfStore;
      let allResults = []
      comunicaQuery(queryString, (results)=>{
        allResults.push(results)
      },quadStore,()=>{resolve(allResults)})
    }
    catch(e) { console.log(e); reject(e) }
 });
}


export default {
  id: se,
  name: 'Search',
  data() {
    return {
      valid: true,
      currentPOD: 'https://helsenorge.'+store.state.serverURL+'/',
      currentContainer: 'https://helsenorge.'+store.state.serverURL+'/home/',
      search: '',
      pdfdata: undefined,
      pdfloaded: false,
      pdfpage: 1,
      searchResponse: '',
      searchArray: [],
      searchArrayOrdered: [],
      uploadDisabled: true,
      noResults: false,
      debug: false,
      scale: undefined,
      loading: false,
      selectedResult: undefined,
    }
  },
  methods: {
      scrollMeTo(refName) {
        var element = this.$refs[refName];
        var top = element.offsetTop;
        window.scrollTo(0, top);
      },
      checklogin(){
        console.log(window.solid.session.info);
        if (window.solid.session.info.isLoggedIn){
          console.log("Test logged in");
        } else {
          console.log("Is logged out, reroute");
          this.$router.push({ path: '/' })
        }
      },
      async runSearch(){
        this.loading = true;
        this.noResults = false;
        searchRdfStore = $rdf.graph();
        this.searchArrayOrdered = [];
        console.log("Searched for: ", this.search);
        let uri = 'https://espen.'+ store.state.serverURL +'/search/'+encodeURIComponent(this.search);
        try {
          let res = await window.solid.session.fetch(
            uri, {
              method: "GET",
              credentials: "include",
              headers: {
                "Accept": "text/turtle"
              },
          }).then(res => res.text());
          if(res.length == 0){
            this.noResults = true;
          }
          console.log("Response: "+res);
          //this.searchResponse = res;
          $rdf.parse(res, searchRdfStore, uri, 'text/turtle');
          // Add URI list by rank
          searchRdfStore.statements.forEach((item, i) => {
            this.searchArray.push(item.subject.value+" --> "+item.predicate.value+" --> "+item.object.value);
            if(item.predicate.value == ns.NEO('m_rank').value){
              this.searchArrayOrdered.push({ rank: item.object.value, type: 'waiting', subjectURI: item.subject.value, title: '', subtitle: '', text: '', filename: '', page: '', pageURI: '', fileURI: '', selected: '#FFFFFF' });
            }
          });

          // Sorting the array by rank ---
          this.searchArrayOrdered = this.searchArrayOrdered.sort(function (a, b) {
            return a.rank - b.rank;
          });
          // End sorting-----
          console.log(this.searchArrayOrdered);
          this.requestSearchResults();
          return res;
        } catch (error) {
          console.log(error);
          console.log("Search failed");
        }
      },
      async requestSearchResults(){
        let didSet = await this.searchArrayOrdered.forEach((item, i) => {
          let tripleArray = searchRdfStore.match($rdf.sym(item.subjectURI), ns.RDF("type"), null);
          tripleArray.forEach(item2 => {
            console.log(item2);
            if(item2.object.value.includes(ns.SIO("SIO_000110").value) || item2.object.value.includes(ns.SIO("SIO_000015").value)){
              console.log("Found a paragraph!!!!");
              item.text = searchRdfStore.match($rdf.sym(item.subjectURI), ns.SCHEMA("text"), null)[0].object.value;
              if(item.text.length >= 3){ // Should make a better check if it is a sentence or more.
                item.type = 'paragraph';
                if(searchRdfStore.match(null, ns.SIO("SIO_000202"), $rdf.sym(item.subjectURI)).length == 0){
                  this.fetchSearchResultURI(item.subjectURI);
                }
                try {
                  let pageURI = searchRdfStore.match(null, ns.SIO("SIO_000202"), $rdf.sym(item.subjectURI))[0].subject.value;
                  item.pageURI = pageURI;
                  searchRdfStore.match(null, ns.SIO("SIO_000202"), $rdf.sym(pageURI)).forEach(fileuri => {
                    item.fileURI = fileuri.subject.value;
                  });
                  if(searchRdfStore.match($rdf.sym(pageURI), ns.RDF("type"), ns.FABIO('Page'))[0].subject.value.length >= 0){
                    let pageName = "";
                    searchRdfStore.match($rdf.sym(pageURI), ns.RDFS("label"), null).forEach(pagename => {
                      pageName = pagename.object.value;
                      item.filename = pageName;
                      item.title = decodeURI(pageName.substring(0, pageName.lastIndexOf('.'))) || decodeURI(pageName); // Removes the file extension
                      if(item.page.includes("_")) item.page = item.page.substring(item.page.indexOf('_') + 1);
                      item.title = item.title.substring(0, item.title.lastIndexOf('_')) || item.title; // Removes value after the _ underline
                    });
                    if(pageName == "") this.fetchSearchResultURI(item.subjectURI);
                  }
                } catch (error) {
                  console.log(error);
                }
              } else {
                item.type = 'word';
              }
            } else if (item2.object.value.includes(ns.REG("file").value) || item2.object.value.includes(ns.OPMV("Artifact").value)){
              console.log("Found a file!!!!");
              item.title = searchRdfStore.match($rdf.sym(item.subjectURI), ns.RDFS("label"), null)[0].object.value;
              if(item2.subject.value.charAt(item2.subject.value.length-4) === "." || item2.subject.value.charAt(item2.subject.value.length-5) === "."){ // Checks if URI is from a file. with 3 or 4 characters after .
                item.type = 'file';
              } else {
                item.type = 'page';
              }
            } else if (item2.object.value.includes(ns.FOAF("Person").value)){
              console.log("Found a person!!!!");
              item.title = searchRdfStore.match($rdf.sym(item.subjectURI), ns.RDFS("label"), null)[0].object.value;
              item.type = 'person';
            } else if (item2.object.value.includes(ns.SIO("SIO_000114").value)){
              // Found Word
              item.type = 'word';
            } else if (item2.object.value.includes(ns.NEO("a_titleblock").value)){
              // Found Titleblock
              item.type = 'titleblock';
            } else if (item2.object.value.includes(ns.SIO("SIO_000135").value)){
              // Found Definition
              item.type = 'definition';
            } else if (item2.object.value.includes(ns.FABIO("Page").value)){
              // Found Page
              item.type = 'page';
            } else if (item2.object.value.includes(ns.NEO("s_tagged-object").value)){
              // Found TAG
              item.title = searchRdfStore.match($rdf.sym(item.subjectURI), ns.TAG("tag"), null)[0].object.value;
              item.text = item.subjectURI;
              item.type = 'tag';
            } else if (item2.object.value.includes(ns.SIO("SIO_000000").value)){
              // Found Word
              item.type = 'entity';
            } else {
              //item.type = 'none';
            }
          });
          
          // Try to request each URI - Temporarily unavailable
          /*let done = ur.fetchAndSaveTurtle(item.subject).then((result) => {
            let tripleArray = store.state.rs.rdfStore.match($rdf.sym(item.subject), ns.RDF("type"), null);
            tripleArray.forEach(item2 => {
              if(item2.object.value.includes(ns.REG("file").value)){
                console.log("Found a file!!!!");
              }
            });
            return result;
          });*/
        });
        this.searchArrayOrdered.forEach((item, i) => {
          if(item.type == 'waiting'){
              try{
                item.title = searchRdfStore.match($rdf.sym(item.subjectURI), ns.RDFS("label"), null)[0].object.value;
              } catch (error) {
                console.log(error);
                //this.searchArrayOrdered.splice(i, 1);
              }
              item.filename = item.subjectURI;
              item.type = 'other';
          }
        });
        this.loading = false;
      },
      async fetchSearchResultURI(resultURI){
        console.log("Result URI:",resultURI);
        let resultData = ur.fetchAndSaveTurtle(resultURI, true).then((successBool) => {
          try{
            let item = this.searchArrayOrdered.find(element => element.subjectURI === resultURI);
            let pageURI = store.state.rs.rdfStore.match(null, ns.SIO("SIO_000202"), $rdf.sym(item.subjectURI))[0].subject.value;
            console.log(pageURI);
            let pageData = ur.fetchAndSaveTurtle(pageURI, true).then((successBool) => {
              item.page = store.state.rs.rdfStore.match($rdf.sym(pageURI), ns.SIO("SIO_000787"), null)[0].object.value;
            });
            if(store.state.rs.rdfStore.match($rdf.sym(pageURI), ns.RDF("type"), ns.FABIO('Page'))[0].subject.value.length >= 0){
              let pageName = store.state.rs.rdfStore.match($rdf.sym(pageURI), ns.RDFS("label"), null)[0].object.value;
              item.filename = pageName;
              item.title = pageName.substring(0, pageName.lastIndexOf('.')) || pageName; // Removes the file extension
              item.title = item.title.substring(0, item.title.lastIndexOf('_')) || item.title; // Removes value after the _ underline
            }
            if(store.state.rs.rdfStore.match(null, ns.SIO("SIO_000202"), $rdf.sym(pageURI))[0].subject.value.length >= 0){
              item.fileURI = store.state.rs.rdfStore.match(null, ns.SIO("SIO_000202"), $rdf.sym(pageURI))[0].subject.value;
            }
          } catch (error) {
            console.log(error);
          }
        });
      },
      getTripleMatches(tripleArray, tripleGraph){
        let tripleResult = [];
        tripleArray.forEach((item, i) => {
          if(i==0){
            //console.log("S: "+tripleArray[i].subject+" P: "+tripleArray[i].predicate+" O: "+tripleArray[i].object);
            tripleGraph.match(tripleArray[i].subject, tripleArray[i].predicate, tripleArray[i].object).forEach(st => {
              tripleResult.push(st);
            });
          } else {
            tripleGraph.match(tripleArray[i].subject, tripleArray[i].predicate, tripleArray[i].object).forEach(st => {
              if(tripleResult.includes(st)){
                tripleResult = this.arrayRemove(tripleResult, st);
                tripleResult.push(st);
              } else {
                tripleResult.push(st);
              }
            });
          }
        });
        return tripleResult;
      },
      async getPDF(pdfURI, page){
        console.log("Opening PDF URI: "+pdfURI);
        this.loading = true;
        this.pdfloaded = false;
        this.pdfdata = undefined;
        try {
          this.pdfpage = parseInt(page);
        } catch (error) {
          this.pdfpage = 1;
        } 
        this.searchArrayOrdered.forEach((item, i) => {
          if(item.subjectURI == pdfURI || item.pageURI == pdfURI){
            item.selected = "#EEFEFF";
          } else {
            item.selected = "#FFFFFF";
          }
        });
        try {
          console.log(pdfURI);
          const res = await window.solid.session.fetch(
            pdfURI, {
              method: "GET",
              credentials: "include",
              });
            let filedata = await res.arrayBuffer();
            let fileurl = URL.createObjectURL(new Blob([filedata], { type: "application/pdf"}));
            this.pdfdata = pdf.createLoadingTask(fileurl);
            this.pdfdata.then(pdf => {
              //console.log("Number of pages: ",pdf.numPages);
              this.pdfloaded = true;
              this.loading = false;
            });
        } catch (error) {
          console.log(error);
        }
      },
      clearSearch(){
        this.searchArrayOrdered = [];
        this.searchArray = [];
        this.search = '';
      },
      arrayRemove(arr, value) {
        return arr.filter(function(ele){
            return ele != value;
        });
      },
  },
  computed: {
      svgFile() {
        return (filename) => getIcon(filename).svg;
      },
  },
  watch: {
    search(){
      this.noResults = false;
    },
  },
