        <v-icon x-large v-else>mdi-earth</v-icon>
      </v-btn>
      <v-btn href="" target="_blank" @click="followLink('ImportData')" text>
        <span class="mr-2">{{ $t("button_importdata") }}</span>
        <v-icon v-if="window.width>=1000">mdi-file-import</v-icon>
        <v-icon x-large v-else>mdi-file-import</v-icon>
      </v-btn>
      <v-btn href="" target="_blank" @click="followLink('FilesLib')" text>
        <span class="mr-2">{{ $t("button_fileslib") }}</span>
        <v-icon v-if="window.width>=1000">mdi-file</v-icon>
        <v-icon x-large v-else>mdi-file</v-icon>
      </v-btn>
      <v-btn href="" target="_blank"  @click="followLink('Capacity')" text>
        <span class="mr-2">{{ $t("button_capacity") }}</span>
        <v-icon v-if="window.width>=1000">mdi-hospital-building</v-icon>
        <v-icon x-large v-else>mdi-hospital-building</v-icon>
      </v-btn>
      <v-btn href="" target="_blank"  @click="followLink('WorkList')" text>
        <span class="mr-2">Arbeidsliste</span>
        <v-icon v-if="window.width>=1000">mdi-list</v-icon>
        <v-icon x-large v-else>mdi-list</v-icon>
      </v-btn>
      <v-btn href="" target="_blank" @click="followLink('Search')" text>
        <span class="mr-2">{{ $t("button_search") }}</span>
        <v-icon v-if="window.width>=1000">mdi-magnify</v-icon>
        <v-icon x-large v-else>mdi-magnify</v-icon>
      </v-btn>

      <button
        v-for="entry in languages"
        :key="entry.title"
        @click="changeLocale(entry.language)"
      >
        <flag :iso="entry.flag" v-bind:squared="false" /> {{ entry.title }}
      </button>

      <v-menu
        v-if="isLoggedIn"
        :close-on-content-click="false"
        :nudge-width="200"
        offset-x
      >
        <template v-slot:activator="{ on, attrs }">
          <v-list-item-avatar color="blue" size="48" v-bind="attrs" v-on="on">
            <span class="white--text text-h5">{{ loggedInInitials }}</span>
          </v-list-item-avatar>
        </template>
        <v-card>
          <v-list>
            <v-list-item>
              <v-list-item-avatar color="blue" size="48">
                <span class="white--text text-h5">{{ loggedInInitials }}</span>
              </v-list-item-avatar>

              <v-list-item-content>
                <v-list-item-title>{{ loggedInName }}</v-list-item-title>
                <v-list-item-subtitle>{{ webId }}</v-list-item-subtitle>
              </v-list-item-content>
            </v-list-item>
          </v-list>
          <v-divider></v-divider>
          <v-list-item-content>
            <v-list-item-subtitle>{{
              $t("session_expires") + loginExpire
            }}</v-list-item-subtitle>
          </v-list-item-content>
          <v-divider></v-divider>
          <v-card-actions>
            <v-spacer></v-spacer>

            <v-btn :to="{ name: 'Logout' }" text>
              <span class="mr-3">{{ $t("button_logout") }}</span>
              <v-icon>mdi-logout</v-icon>
            </v-btn>
          </v-card-actions>
        </v-card>
      </v-menu>
    </v-app-bar>

    <v-main>
      <router-view />
    </v-main>
  </v-app>
</template>


<script>
import i18n from './plugins/i18n.js'
import store from './store';

export default {
  name: 'App',

  data: () => ({
      languages: [
          { flag: 'us', language: 'en' },
          { flag: 'no', language: 'no' }
      ],
      isLoggedIn: false,
      webId: "",
      loggedInName: "",
      loggedInInitials: "",
      loginExpire: "",
      window: {
        width: 0,
        height: 0
      }
  }),
  created() {
    window.addEventListener('resize', this.handleResize);
    this.handleResize();
  },
  destroyed() {
    window.removeEventListener('resize', this.handleResize);
  },
  methods: {
    changeLocale(locale) {
      i18n.locale = locale;
    },
    followLink(linkName){
      if(!this.$route.path.includes(linkName)){
        this.$router.push({path: linkName, query: {location: this.$route.query.location, select: this.$route.query.select} });
      }
    },
    handleResize() {
      this.window.width = window.innerWidth;
      this.window.height = window.innerHeight;
    }
  },
  watch: {
    "$store.state.isLoggedIn": function (val) {
      this.isLoggedIn = store.state.isLoggedIn;
    },
    "$store.state.webId": function (val) {
      this.webId = store.state.webId;
    },
    "$store.state.loggedInName": function (val) {
      this.loggedInName = store.state.loggedInName;
    },
    "$store.state.loggedInInitials": function (val) {
      this.loggedInInitials = store.state.loggedInInitials;
    },
    "$store.state.loginExpire": function (val) {
      this.loginExpire = store.state.loginExpire;
    }
  }
};
</script>
